#include<bits/stdc++.h>
using namespace std;
long long a[300010],sum[300010],max1[300010],blksiz,blk[300010],blkl[300010],blkr[300010];
void pushupd(long long x)
{
    if(max1[x]<2)
    {
        return;
    }
    sum[x]=0;
    max1[x]=LLONG_MIN;
    for(long long i=blkl[x];i<=blkr[x];i++)
    {
        a[i]=floor(sqrt(a[i]));
        sum[x]+=a[i];
        max1[x]=max(max1[x],a[i]);
    }
}
void calc(long long x)
{
    sum[x]=0;
    max1[x]=LLONG_MIN;
    for(long long i=blkl[x];i<=blkr[x];i++)
    {
        sum[x]+=a[i];
        max1[x]=max(max1[x],a[i]);
    }
}
void update(long long l,long long r)
{
    if(blk[l]==blk[r])
    {
        for(long long i=l;i<=r;i++)
        {
            a[i]=floor(sqrt(a[i]));
        }
        calc(blk[l]);
        return;
    }
    for(long long i=l;i<=blkr[blk[l]];i++)
    {
        a[i]=floor(sqrt(a[i]));
    }
    calc(blk[l]);
    for(long long i=blkl[blk[r]];i<=r;i++)
    {
        a[i]=floor(sqrt(a[i]));
    }
    calc(blk[r]);
    for(long long i=blk[l]+1;i<blk[r];i++)
    {
        pushupd(i);
    }
}
long long getsum(long long l,long long r)
{
    long long ans=0;
    if(blk[l]==blk[r])
    {
        for(long long i=l;i<=r;i++)
        {
            ans=ans+a[i];
        }
        return ans;
    }
    for(long long i=l;i<=blkr[blk[l]];i++)
    {
        ans=ans+a[i];
    }
    for(long long i=blkl[blk[r]];i<=r;i++)
    {
        ans=ans+a[i];
    }
    for(long long i=blk[l]+1;i<blk[r];i++)
    {
        ans=ans+sum[i];
    }
    return ans;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    blksiz=sqrt(n);
    for(long long i=1;blksiz*(i-1)+1<=n;i++)
    {
        blkl[i]=blksiz*(i-1)+1;
        blkr[i]=min(n,blksiz*i);
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        blk[i]=(i+blksiz-1)/blksiz;
        sum[blk[i]]+=a[i];
        max1[blk[i]]=max(max1[blk[i]],a[i]);
    }
    while(n--)
    {
        long long op,l,r;
        scanf("%lld%lld%lld",&op,&l,&r);
        if(op==0)
        {
            update(l,r);
        }
        else
        {
            printf("%lld\n",getsum(l,r));
        }
    }
    return 0;
}
